  1	import * as React from 'react';
  2	import classNames from 'classnames';
  3	import * as _ from 'lodash-es';
  4	import { DndProvider } from 'react-dnd';
  5	import { HTML5Backend } from 'react-dnd-html5-backend';
  6	import { Button, Tooltip } from '@patternfly/react-core';
  7	import {
  8	  GripVerticalIcon,
  9	  MinusCircleIcon,
 10	  PlusCircleIcon,
 11	} from '@patternfly/react-icons';
 12	import { useCustomTranslation } from '../useCustomTranslationHook';
 13	import { AsyncLoader } from './AsyncLoader';
 14	
 15	/**
 16	 * Set up an AsyncComponent to wrap the name-value-editor to allow on demand loading to reduce the
 17	 * vendor footprint size.
 18	 */
 19	export const LazyNameValueEditor = (props) => (
 20	  <AsyncLoader
 21	    loader={() => import('./NameValueEditor').then((c) => c.NameValueEditor)}
 22	    {...props}
 23	  />
 24	);
 25	
 26	const withDragDropContext =
 27	  <TProps extends {}>(
 28	    Component: React.ComponentClass<TProps> | React.FC<TProps>
 29	  ) =>
 30	  // eslint-disable-next-line react/display-name
 31	  (props: TProps) => (
 32	    <DndProvider backend={HTML5Backend}>
 33	      <Component {...props} />
 34	    </DndProvider>
 35	  );
 36	
 37	type NameValueEditorProps = {
 38	  nameString: string;
 39	  valueString: string;
 40	  addString: string;
 41	  allowSorting: boolean;
 42	  readOnly: boolean;
 43	  nameValueId: number;
 44	  nameValuePairs: any;
 45	  updateParentData: Function;
 46	  configMaps: {};
 47	  secrets: {};
 48	  addConfigMapSecret: boolean;
 49	  toolTip: string;
 50	  PairElementComponent: React.FC<PairElementProps>;
 51	  onLastItemRemoved: () => void;
 52	  extraProps?: any;
 53	  isAddDisabled?: boolean;
 54	  className?: string;
 55	  hideHeaderWhenNoItems?: boolean;
 56	  IconComponent?: React.FC;
 57	  nameMaxLength?: number;
 58	  valueMaxLength?: number;
 59	  alwaysAllowRemove?: boolean;
 60	};
 61	
 62	export const enum NameValueEditorPair {
 63	  Name = 0,
 64	  Value,
 65	  Index,
 66	}
 67	
 68	export type PairElementProps = {
 69	  nameString: string;
 70	  valueString: string;
 71	  readOnly?: boolean;
 72	  index?: number;
 73	  pair?: any;
 74	  allowSorting?: boolean;
 75	  onChange: any;
 76	  connectDragSource?: (arg: any) => any;
 77	  connectDropTarget?: (args: any) => any;
 78	  isDragging?: () => void;
 79	  onMove: any;
 80	  rowSourceId?: any;
 81	  toolTip: {};
 82	  alwaysAllowRemove?: {};
 83	  onRemove?: any;
 84	  isEmpty: boolean;
 85	  disableReorder: boolean;
 86	  extraProps?: any;
 87	  nameMaxLength?: number;
 88	  valueMaxLength?: number;
 89	};
 90	
 91	const PairElement: React.FC<PairElementProps> = ({
 92	  index,
 93	  onRemove: onRemoveProp,
 94	  onChange,
 95	  isDragging,
 96	  connectDragSource,
 97	  nameString,
 98	  allowSorting,
 99	  readOnly,
100	  pair,
101	  isEmpty,
102	  disableReorder,
103	  toolTip,
104	  valueString,
105	  alwaysAllowRemove,
106	  nameMaxLength,
107	  valueMaxLength,
108	}) => {
109	  const { t } = useCustomTranslation();
110	  const deleteIcon = (
111	    <>
112	      <MinusCircleIcon className="pairs-list__side-btn pairs-list__delete-icon" />
113	      <span className="sr-only">{t('Delete')}</span>
114	    </>
115	  );
116	  const dragButton = (
117	    <div>
118	      <Button
119	        type="button"
120	        className="pairs-list__action-icon"
121	        isDisabled={disableReorder}
122	        variant="plain"
123	        aria-label={t('Drag to reorder')}
124	      >
125	        <GripVerticalIcon className="pairs-list__action-icon--reorder" />
126	      </Button>
127	    </div>
128	  );
129	
130	  const onChangeName = React.useCallback(
131	    (e) => {
132	      onChange(e, index, NameValueEditorPair.Name);
133	    },
134	    [index, onChange]
135	  );
136	
137	  const onChangeValue = React.useCallback(
138	    (e) => {
139	      onChange(e, index, NameValueEditorPair.Value);
140	    },
141	    [index, onChange]
142	  );
143	
144	  const onRemove = React.useCallback(() => {
145	    onRemoveProp(index);
146	  }, [index, onRemoveProp]);
147	
148	  return (
149	    <div
150	      className={classNames(
151	        'row',
152	        isDragging ? 'pairs-list__row-dragging' : 'pairs-list__row'
153	      )}
154	      data-test="pairs-list-row"
155	    >
156	      {allowSorting && !readOnly && (
157	        <div className="col-xs-1 pairs-list__action">
158	          {disableReorder ? dragButton : connectDragSource(dragButton)}
159	        </div>
160	      )}
161	      <div className="col-xs-5 pairs-list__name-field">
162	        <input
163	          type="text"
164	          data-test="pairs-list-name"
165	          className="pf-v6-c-form-control"
166	          placeholder={nameString}
167	          value={pair[NameValueEditorPair.Name]}
168	          onChange={onChangeName}
169	          disabled={readOnly}
170	          maxLength={nameMaxLength}
171	        />
172	      </div>
173	      <div className="col-xs-5 pairs-list__value-field">
174	        <input
175	          type="text"
176	          data-test="pairs-list-value"
177	          className="pf-v6-c-form-control"
178	          placeholder={valueString}
179	          value={pair[NameValueEditorPair.Value] || ''}
180	          onChange={onChangeValue}
181	          disabled={readOnly}
182	          maxLength={valueMaxLength}
183	        />
184	      </div>
185	      {!readOnly && (
186	        <div className="col-xs-1 pairs-list__action">
187	          <Tooltip content={toolTip || t('Remove')}>
188	            <Button
189	              type="button"
190	              data-test="delete-button"
191	              className={classNames({
192	                'pairs-list__span-btns': allowSorting,
193	              })}
194	              onClick={onRemove}
195	              isDisabled={isEmpty && !alwaysAllowRemove}
196	              variant="plain"
197	            >
198	              {deleteIcon}
199	            </Button>
200	          </Tooltip>
201	        </div>
202	      )}
203	    </div>
204	  );
205	};
