207	export const NameValueEditor: React.FC<NameValueEditorProps> =
208	  withDragDropContext(
209	    ({
210	      nameValuePairs,
211	      updateParentData,
212	      nameValueId,
213	      onLastItemRemoved,
214	      addString,
215	      allowSorting,
216	      readOnly,
217	      toolTip,
218	      nameString,
219	      valueString,
220	      extraProps,
221	      isAddDisabled,
222	      className,
223	      hideHeaderWhenNoItems = false,
224	      nameMaxLength,
225	      valueMaxLength,
226	      IconComponent = PlusCircleIcon,
227	      PairElementComponent = PairElement,
228	      alwaysAllowRemove = false,
229	    }) => {
230	      const { t } = useCustomTranslation();
231	
232	      const append = React.useCallback(() => {
233	        updateParentData({
234	          nameValuePairs: nameValuePairs.concat([
235	            ['', '', nameValuePairs.length],
236	          ]),
237	        });
238	      }, [updateParentData, nameValuePairs]);
239	
240	      const remove = React.useCallback(
241	        (i) => {
242	          const nameValuePairsUpdated = _.cloneDeep(nameValuePairs);
243	          nameValuePairsUpdated.splice(i, 1);
244	          nameValuePairsUpdated.forEach((values, index) => (values[2] = index)); // update the indices in order.
245	
246	          updateParentData(
247	            {
248	              nameValuePairs: nameValuePairsUpdated.length
249	                ? nameValuePairsUpdated
250	                : [['', '', 0]],
251	            },
252	            nameValueId
253	          );
254	
255	          if (nameValuePairsUpdated.length === 0 && !!onLastItemRemoved) {
256	            onLastItemRemoved();
257	          }
258	        },
259	        [nameValuePairs, onLastItemRemoved, updateParentData, nameValueId]
260	      );
261	
262	      const change = React.useCallback(
263	        (e, i, type) => {
264	          const nameValuePairsCloned = _.cloneDeep(nameValuePairs);
265	
266	          nameValuePairsCloned[i][
267	            type === NameValueEditorPair.Name
268	              ? NameValueEditorPair.Name
269	              : NameValueEditorPair.Value
270	          ] = e.target.value;
271	          updateParentData(
272	            { nameValuePairs: nameValuePairsCloned },
273	            nameValueId
274	          );
275	        },
276	        [nameValueId, nameValuePairs, updateParentData]
277	      );
278	
279	      const move = React.useCallback(
280	        (dragIndex, hoverIndex) => {
281	          const nameValuePairsUpdated = _.cloneDeep(nameValuePairs);
282	          const movedPair = nameValuePairsUpdated[dragIndex];
283	
284	          nameValuePairsUpdated[dragIndex] = nameValuePairsUpdated[hoverIndex];
285	          nameValuePairsUpdated[hoverIndex] = movedPair;
286	          updateParentData(
287	            { nameValuePairs: nameValuePairsUpdated },
288	            nameValueId
289	          );
290	        },
291	        [nameValuePairs, nameValueId, updateParentData]
292	      );
293	
294	      const nameStringUpdated = nameString || t('Key');
295	      const valueStringUpdated = valueString || t('Value');
296	      const pairElems = nameValuePairs?.map((pair, i) => {
297	        const key = _.get(pair, [NameValueEditorPair.Index], i);
298	        const isEmpty =
299	          nameValuePairs.length === 1 &&
300	          nameValuePairs[0].every((value) => !value);
301	        return (
302	          <PairElementComponent
303	            onChange={change}
304	            index={i}
305	            nameString={nameStringUpdated}
306	            valueString={valueStringUpdated}
307	            allowSorting={allowSorting}
308	            readOnly={readOnly}
309	            pair={pair}
310	            key={key}
311	            onRemove={remove}
312	            onMove={move}
313	            rowSourceId={nameValueId}
314	            isEmpty={isEmpty}
315	            disableReorder={nameValuePairs.length === 1}
316	            toolTip={toolTip}
317	            extraProps={extraProps}
318	            nameMaxLength={nameMaxLength}
319	            valueMaxLength={valueMaxLength}
320	            alwaysAllowRemove={alwaysAllowRemove}
321	          />
322	        );
323	      });
324	      return (
325	        <>
326	          {hideHeaderWhenNoItems && _.isEmpty(pairElems) ? null : (
327	            <>
328	              <div className="row pairs-list__heading">
329	                {!readOnly && allowSorting && (
330	                  <div className="col-xs-1 co-empty__header" />
331	                )}
332	                <div className={classNames('col-xs-5', className)}>
333	                  {nameStringUpdated}
334	                </div>
335	                <div className={classNames('col-xs-5', className)}>
336	                  {valueStringUpdated}
337	                </div>
338	                <div className="col-xs-1 co-empty__header" />
339	              </div>
340	              {pairElems}
341	            </>
342	          )}
343	          <div className="row">
344	            <div className="col-xs-12">
345	              {readOnly ? null : (
346	                <div className="co-toolbar__group co-toolbar__group--left">
347	                  <Button
348	                    className="pf-m-link--align-left"
349	                    data-test="add-button"
350	                    onClick={append}
351	                    type="button"
352	                    variant="link"
353	                    isDisabled={isAddDisabled}
354	                  >
355	                    <IconComponent
356	                      data-test-id="pairs-list__add-icon"
357	                      className="co-icon-space-r"
358	                    />
359	                    {addString ? addString : t('Add more')}
360	                  </Button>
361	                </div>
362	              )}
363	            </div>
364	          </div>
365	        </>
366	      );
367	    }
368	  );

